public class Punto {    public int coordenada_x;    public int coordenada_y;    public Punto(){        this.coordenada_x=0;        this.coordenada_y=0;    }    public Punto(int coordenada_x, int coordenada_y) {        this.coordenada_x = coordenada_x;        this.coordenada_y = coordenada_y;    }    public double calcularDistancia(Punto punto){        return punto.coordenada_y;    }    @Override    public String toString() {        return "El punto tiene las siguientes coordenadas "+                "coordenada x= " + coordenada_x +                ", coordenada y= " + coordenada_y;    }    public int getCoordenada_x() {        return coordenada_x;    }    public void setCoordenada_x(int coordenada_x) {        this.coordenada_x = coordenada_x;    }    public int getCoordenada_y() {        return coordenada_y;    }    public void setCoordenada_y(int coordenada_y) {        this.coordenada_y = coordenada_y;    }}